from tools.analysis.metrics import get_current_month, get_prev_month


class TestGetCurrentMonth:
    def test_returns_yyyy_mm_format(self):
        result = get_current_month()
        assert len(result) == 7
        assert result[4] == "-"

    def test_returns_string(self):
        assert isinstance(get_current_month(), str)

    def test_year_is_reasonable(self):
        year = int(get_current_month()[:4])
        assert 2024 <= year <= 2030

    def test_month_is_valid(self):
        month = int(get_current_month()[5:])
        assert 1 <= month <= 12


class TestGetPrevMonth:
    @pytest.mark.parametrize("month,expected", [
        ("2025-11", "2025-10"),
        ("2025-01", "2024-12"),   # year rollover
        ("2024-12", "2024-11"),
        ("2026-06", "2026-05"),
    ])
    def test_prev_month(self, month, expected):
        assert get_prev_month(month) == expected

    def test_returns_yyyy_mm_format(self):
        result = get_prev_month("2025-10")
        assert len(result) == 7
        assert result[4] == "-"

    def test_no_arg_uses_current_month(self):
        result = get_prev_month()
        assert isinstance(result, str)
        assert len(result) == 7


