from tools.analysis.subscriptions import detect_and_mark_recurring, get_recurring_subscriptions


class TestDetectAndMarkRecurring:
    def test_returns_list(self, populated_db):
        result = detect_and_mark_recurring(conn=populated_db)
        assert isinstance(result, list)

    def test_netflix_detected_as_recurring(self, populated_db):
        # Netflix appears in all 3 months with same amount = recurring
        result = detect_and_mark_recurring(conn=populated_db)
        merchants = [str(r.get("merchant") or r.get("clean_merchant") or "") for r in result]
        assert any("Netflix" in m or "NETFLIX" in m for m in merchants)

    def test_spotify_detected_as_recurring(self, populated_db):
        result = detect_and_mark_recurring(conn=populated_db)
        merchants = [str(r.get("merchant") or r.get("clean_merchant") or "") for r in result]
        assert any("Spotify" in m or "SPOTIFY" in m for m in merchants)

    def test_marks_is_recurring_in_db(self, populated_db):
        detect_and_mark_recurring(conn=populated_db)
        rows = populated_db.execute(
            "SELECT COUNT(*) FROM transactions WHERE is_recurring=1"
        ).fetchone()
        assert rows[0] > 0

    def test_empty_db_returns_empty(self, db):
        result = detect_and_mark_recurring(conn=db)
        assert result == [] or isinstance(result, list)


class TestGetRecurringSubscriptions:
    def test_returns_list(self, populated_db):
        detect_and_mark_recurring(conn=populated_db)
        result = get_recurring_subscriptions(conn=populated_db)
