    def test_recurring_merchants_present_after_detection(self, populated_db):
        detect_and_mark_recurring(conn=populated_db)
        result = get_recurring_subscriptions(conn=populated_db)
        merchants = [str(r.get("merchant") or r.get("clean_merchant") or "") for r in result]
        assert any("Netflix" in m or "Spotify" in m for m in merchants)

    def test_empty_before_detection(self, populated_db):
        # Without running detect first, is_recurring=0 for all → empty
        result = get_recurring_subscriptions(conn=populated_db)
        # Depends on whether seed data has is_recurring set
